#include <stdio.h>
#include <stdlib.h>
#include <omp.h>

#include "../common.h"
#include "../util/timer/timer.h"
#include "./kernel_cpu_2.h"

void 
kernel_cpu_2(	int cores_arg,

				knode *knodes,
				long knodes_elem,

				int order,
				long maxheight,
				int count,

				long *currKnode,
				long *offset,
				long *lastKnode,
				long *offset_2,
				int *start,
				int *end,
				int *recstart,
				int *reclength)
{
	// timer
	long long time0;
	long long time1;
	long long time2;
	long long time3;
	long long time4;
	long long time5;
	long long time6;

	time0 = get_time();

	// set number of threads
	omp_set_num_threads(cores_arg);

	time1 = get_time();

	// process levels of the tree
	#pragma omp parallel for
	for(int i = 0; i < count; i++){
		for(int j = 0; j < maxheight; j++){
			for(int k = 0; k < order; k++){
				if((knodes[currKnode[i]].keys[k] <= start[i]) && (knodes[currKnode[i]].keys[k+1] > start[i])){
					if(knodes[currKnode[i]].indices[k] < knodes_elem){
						offset[i] = knodes[currKnode[i]].indices[k];
					}
				}
				if((knodes[lastKnode[i]].keys[k] <= end[i]) && (knodes[lastKnode[i]].keys[k+1] > end[i])){
					if(knodes[lastKnode[i]].indices[k] < knodes_elem){
						offset_2[i] = knodes[lastKnode[i]].indices[k];
					}
				}
			}

			// set for next tree level
			currKnode[i] = offset[i];
			lastKnode[i] = offset_2[i];
		}

		// process leaves
		// Find the index of the starting record
		for(int k = 0; k < order; k++){
			if(knodes[currKnode[i]].keys[k] == start[i]){
				recstart[i] = knodes[currKnode[i]].indices[k];
			}
		}

		// Find the index of the ending record
		for(int k = 0; k < order; k++){
			if(knodes[lastKnode[i]].keys[k] == end[i]){
				reclength[i] = knodes[lastKnode[i]].indices[k] - recstart[i] + 1;
			}
		}
	}

	time6 = get_time();

	// display timing
	printf("Time spent in different stages of CPU KERNEL:\n");
	printf("%15.12f s, %15.12f % : CPU: SET NUMBER OF THREADS\n", (float) (time1-time0) / 1000000, (float) (time1-time0) / (float) (time6-time0) * 100);
	printf("%15.12f s, %15.12f % : CPU: PROCESSING\n", (float) (time6-time1) / 1000000, (float) (time6-time1) / (float) (time6-time0) * 100);
	printf("Total time:\n");
	printf("%.12f s\n", (float) (time6-time0) / 1000000);
}
